# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

defmodule MyAppWeb.PostLive do
  use Phoenix.LiveView

  def live(assigns) do
    LiveView.render(MyAppWeb, "__POST__", assigns: assigns)
  end

  def on_mount(_params) do
    @post = %{content: "Your raw HTML content here"}
  end
end

defmodule MyAppWeb.HtmlLive do
  use Phoenix.LiveView

  def live(assigns) do
    LiveView.render(MyAppWeb, "__HTML__", assigns: assigns)
  end

  def render_post(post) do
    ~> html do
      div class: "post", do: raw(post.content)
    end
  end
end

defmodule MyAppWeb do
  use Phoenix.Web, otp_app: :my_app

  pipeline :api do
    plug :accepts, ["html"]
  end

  scope "/", MyAppWeb
  live "/live/post", PostLive
  live "/live/html", HtmlLive
end